<span class="line">    userEvent<span class="token punctuation">.</span><span class="token function">click</span><span class="token punctuation">(</span>screen<span class="token punctuation">.</span><span class="token function">getByText</span><span class="token punctuation">(</span><span class="token string">&quot;Print input&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
